 34	static int modulus_rx(rlc_entity_am_t *entity, int a)
 35	{
 36	  /* as per 36.322 7.1, modulus base is vr(r) and modulus is 1024 for rx */
 37	  int r = a - entity->vr_r;
 38	  if (r < 0) r += 1024;
 39	  return r;
 40	}
 41	
 42	/* used in both RX and TX processing */
 43	static int modulus_tx(rlc_entity_am_t *entity, int a)
 44	{
 45	  /* as per 36.322 7.1, modulus base is vt(a) and modulus is 1024 for tx */
 46	  int r = a - entity->vt_a;
 47	  if (r < 0) r += 1024;
 48	  return r;
 49	}
 50	
 51	static int sn_in_recv_window(void *_entity, int sn)
 52	{
 53	  rlc_entity_am_t *entity = _entity;
 54	  int mod_sn = modulus_rx(entity, sn);
 55	  /* we simplify vr(r)<=sn<vr(mr). base is vr(r) and vr(mr) = vr(r) + 512 */
 56	  return mod_sn < 512;
 57	}
