 88	static int rlc_am_segment_full(rlc_entity_am_t *entity, int sn)
 89	{
 90	  rlc_rx_pdu_segment_t *l = entity->rx_list;
 91	  int last_byte;
 92	  int new_last_byte;
 93	
 94	  last_byte = -1;
 95	  while (l != NULL) {
 96	    if (l->sn == sn)
 97	      break;
 98	    l = l->next;
 99	  }
100	  while (l != NULL && l->sn == sn) {
101	    if (l->so > last_byte + 1)
102	      return 0;
103	    if (l->is_last)
104	      return 1;
105	    new_last_byte = l->so + l->size - l->data_offset - 1;
106	    if (new_last_byte > last_byte)
107	      last_byte = new_last_byte;
108	    l = l->next;
109	  }
110	  return 0;
111	}
