115	{
116	  int rf;
117	  int sn;
118	
119	  r->sdu_offset = r->start->data_offset;
120	
121	  rlc_pdu_decoder_init(&r->dec, r->start->data, r->start->size);
122	
123	  rlc_pdu_decoder_get_bits(&r->dec, 1);            /* dc */
124	  rf    = rlc_pdu_decoder_get_bits(&r->dec, 1);
125	  rlc_pdu_decoder_get_bits(&r->dec, 1);            /* p */
126	  r->fi = rlc_pdu_decoder_get_bits(&r->dec, 2);
127	  r->e  = rlc_pdu_decoder_get_bits(&r->dec, 1);
128	  sn    = rlc_pdu_decoder_get_bits(&r->dec, 10);
129	  if (rf) {
130	    rlc_pdu_decoder_get_bits(&r->dec, 1);          /* lsf */
131	    r->so = rlc_pdu_decoder_get_bits(&r->dec, 15);
132	  } else {
133	    r->so = 0;
134	  }
135	
136	  if (r->e) {
137	    r->e       = rlc_pdu_decoder_get_bits(&r->dec, 1);
138	    r->sdu_len = rlc_pdu_decoder_get_bits(&r->dec, 11);
139	  } else
140	    r->sdu_len = r->start->size - r->sdu_offset;
141	
142	  /* new sn: read starts from PDU byte 0 */
143	  if (sn != r->sn) {
144	    r->pdu_byte = 0;
145	    r->sn = sn;
146	  }
147	
148	  r->data_pos = r->start->data_offset + r->pdu_byte - r->so;
149	
150	  /* TODO: remove this check, it is useless, data has been validated before */
151	  if (r->pdu_byte < r->so) {
152	    LOG_E(RLC, "%s:%d:%s: fatal\n", __FILE__, __LINE__, __FUNCTION__);
153	    exit(1);
154	  }
155	
156	  /* if pdu_byte is not in [so .. so+len-1] then all bytes from this segment
157	   * have already been consumed
158	   */
159	  if (r->pdu_byte >= r->so + r->start->size - r->start->data_offset)
160	    return 0;
161	
162	  /* go to correct SDU */
163	  while (r->pdu_byte >= r->so + (r->sdu_offset - r->start->data_offset) + r->sdu_len) {
164	    r->sdu_offset += r->sdu_len;
165	    if (r->e) {
166	      r->e       = rlc_pdu_decoder_get_bits(&r->dec, 1);
167	      r->sdu_len = rlc_pdu_decoder_get_bits(&r->dec, 11);
168	    } else {
169	      r->sdu_len = r->start->size - r->sdu_offset;
170	    }
171	  }
172	
173	  return 1;
174	}
